text:
{
  "formal_minutes": {
    "회의정보": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"]
    },
    "확정결정": [
      {
        "주제": "공개 릴리스 목표 시각",
        "내용": "스모크 테스트 통과 시 금요일 15:00 KST를 공개 릴리스 목표로 확정."
      },
      {
        "주제": "packageName 불일치 대응 원칙",
        "내용": "불일치 발생 시 먼저 패키지 설정을 점검하고, 계약(컨트랙트) 자체가 잘못된 경우에만 스크립트 검토."
      }
    ],
    "기각된제안": [
      {
        "제안자": "Hara",
        "제안": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경",
        "결론": "기각"
      }
    ],
    "내부스트레치골": [
      {
        "내용": "수요일 릴리스 제안은 내부 스트레치 골이며 확정 일정이 아님."
      }
    ],
    "비결정/미확정사항": [
      {
        "내용": "README 설치 단계는 가능하면 목요일까지 검토 제안이 있었으나 담당자 미지정."
      },
      {
        "내용": "Hara의 tarball 경로 확인은 Minjun의 스모크 결과 공유 이후 수행, 정확한 기한 미설정."
      }
    ],
    "리스크": [
      {
        "내용": "tarball 경로 오류 시 릴리스 지연 가능."
      },
      {
        "내용": "README 설치 단계가 오래된 경우 릴리스 노트가 사용자에게 오해를 줄 수 있음."
      }
    ],
    "오픈질문": [
      {
        "질문": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "질문": "릴리스 노트에 내부 수요일 스트레치 골을 명시할 것인가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음(명시적 확정 액션)"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음(명시적 확정 액션)"
    },
    {
      "owner": "미정",
      "task": "README 설치 단계 검토(가능하면 목요일)",
      "due": "목요일(가능 시, 확정 아님)",
      "status": "미확정",
      "source_certainty": "중간(제안만 존재, 담당자 없음)"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로 점검",
      "due": "미정",
      "status": "부분확정(업무는 확인, 기한 미확정)",
      "source_certainty": "중간(행동은 명시, 기한 없음)"
    }
  ],
  "followup_note": {
    "다음확인사항": [
      "Minjun 스모크 테스트 결과(금요일 10:00 KST 목표) 수신 여부 확인",
      "Doyun의 action_items.md 트리아지 노트 작성 완료 여부 확인",
      "tarball 경로 점검 결과 및 릴리스 영향도 확인",
      "README 설치 단계 검토 담당자 지정 필요",
      "최종 릴리스 승인 권한자 확정 필요",
      "릴리스 노트에 수요일 내부 스트레치 골 언급 여부 결정 필요"
    ],
    "주의사항": [
      "수요일 일정은 내부 스트레치 골로만 취급하고 대외 확정 일정으로 표현하지 말 것",
      "packageName 불일치 무시를 위한 스크립트 변경안은 기각되었음을 유지할 것"
    ]
  },
  "non_invention_rules": [
    "고객명 또는 외부 파트너를 추가로 만들지 않는다.",
    "예산 수치/승인 상태를 만들지 않는다.",
    "보안 사고를 만들지 않는다.",
    "프로덕션 장애 사실을 만들지 않는다.",
    "법무 승인 요건을 만들지 않는다.",
    "미지정 owner를 임의 지정하지 않는다.",
    "미합의 마감시한을 임의 확정하지 않는다."
  ]
}
